mapper.update:
UPDATE d_order_async_message
SET message_status = #{sendFailedStatus},
    last_error = #{lastError},
    edit_time = #{now}
WHERE message_key = #{messageKey}
  AND status = 1

UPDATE d_order_async_message
SET message_status = #{consumingStatus},
    edit_time = #{now}
WHERE message_key = #{messageKey}
  AND message_status IN

      #{fromStatus}

  AND status = 1

UPDATE d_order_async_message
SET message_status = #{succeededStatus},
    last_error = NULL,
    edit_time = #{now}
WHERE message_key = #{messageKey}
  AND status = 1
